SELECT CH.SEMESTRE FROM CALC_HORA_AULA_MEDIA CH JOIN SERVIDOR S ON S.PK_SIAPE = CH.SIAPE WHERE CH.ANO = 2024 AND LOWER(CH.SIGLA_CAMPUS) = LOWER('jat') AND LOWER(CH.AREA_INGRESSO) LIKE LOWER('%engenharia eletrica%') AND LOWER(S.CONTRATO) = LOWER('efetivos') GROUP BY CH.SEMESTRE HAVING COUNT(DISTINCT CH.SIAPE) = 3 ORDER BY CH.SEMESTRE